// Reúne todos los datos y clasifica el tipo de entrada del lead
const normalData = $('📋 Normalizar datos').item.json;
const contactData = items[0].json;

// Parsear historial de conversación
let history = [];
try {
  history = JSON.parse(contactData.conversation_history || '[]');
  if (!Array.isArray(history)) history = [];
} catch(e) {
  history = [];
}

// Añadir el mensaje actual del lead al historial
history.push({
  role: 'user',
  content: normalData.message_text,
  timestamp: new Date().toISOString()
});

// Mantener solo los últimos 10 mensajes
if (history.length > 10) {
  history = history.slice(-10);
}

// Clasificar tipo de entrada
// PRIORIDAD: conversación activa > tipo 4 > tipo 1 > tipo 2 > tipo 3 (catch-all)
const msgLower = (normalData.message_text || '').toLowerCase();
const currentStage = contactData.lifecycle_stage || 'nuevo_lead';
let entry_type = contactData.entry_type || '';

let entry_label = '3_catch_all'; // default

if (currentStage !== 'nuevo_lead') {
  entry_label = '0_conversacion_activa';
} else if (/precio|curso|comprar|c[oó]mo funciona|que incluye|cu[aá]nto|info|informaci[oó]n|programa|servicio/.test(msgLower)) {
  entry_label = '4_quiere_comprar';
  if (!entry_type) entry_type = '4';
} else if (msgLower.includes('quiero')) {
  entry_label = '1_keyword';
  if (!entry_type) entry_type = '1';
} else if (contactData.entry_type === 'lead_magnet') {
  entry_label = '2_lead_magnet';
  entry_type = 'lead_magnet';
} else {
  entry_label = '3_catch_all';
  if (!entry_type) entry_type = '3';
}

return [{
  json: {
    contact_id: normalData.contact_id,
    contact_name: normalData.contact_name,
    conversation_id: normalData.conversation_id,
    lifecycle_stage: currentStage,
    lead_temperature: contactData.lead_temperature || 'frio',
    main_problem: contactData.main_problem || '',
    entry_type: entry_type,
    entry_label: entry_label,
    conversation_history: history,
    conversation_history_str: JSON.stringify(history),
    conversation_summary: contactData.conversation_summary || '',
    message_text: normalData.message_text
  }
}];

