const aiRaw = items[0].json.choices[0].message.content;
const contextData = $('🧠 Construir contexto + clasificar entrada').item.json;

let aiResponse;
try {
  aiResponse = JSON.parse(aiRaw);
} catch(e) {
  console.log('ERROR parsing AI:', e.message);
  aiResponse = {
    messages: [aiRaw.substring(0, 500)],
    send_video: false,
    send_audio: false,
    send_calendly: false,
    new_stage: contextData.lifecycle_stage,
    new_temperature: contextData.lead_temperature,
    detected_problem: contextData.main_problem,
    conversation_summary: contextData.conversation_summary
  };
}

// Actualizar historial con mensajes del bot
let history = contextData.conversation_history || [];
(aiResponse.messages || []).forEach(function(msg) {
  if (msg && msg.trim()) {
    history.push({
      role: 'assistant',
      content: msg,
      timestamp: new Date().toISOString()
    });
  }
});
if (history.length > 10) history = history.slice(-10);

// Determinar stage final con lógica de prioridad
let finalStage = aiResponse.new_stage || contextData.lifecycle_stage;
if (aiResponse.send_video) finalStage = 'video_enviado';
if (aiResponse.send_audio) finalStage = 'cualificado';
if (aiResponse.send_calendly && !aiResponse.send_audio) finalStage = 'llamada_agendada';

return [{
  json: {
    contact_id: contextData.contact_id,
    contact_name: contextData.contact_name,
    conversation_id: contextData.conversation_id,
    entry_type: contextData.entry_type,
    messages: aiResponse.messages || [],
    send_video: aiResponse.send_video || false,
    send_audio: aiResponse.send_audio || false,
    send_calendly: aiResponse.send_calendly || false,
    new_stage: finalStage,
    new_temperature: aiResponse.new_temperature || contextData.lead_temperature,
    detected_problem: aiResponse.detected_problem || contextData.main_problem || '',
    conversation_summary: aiResponse.conversation_summary || contextData.conversation_summary || '',
    updated_history: JSON.stringify(history)
  }
}];

const data = items[0].json;
const messages = data.messages || [];
const contactId = data.contact_id;
const channelId = process.env.RESPOND_IO_CHANNEL_ID;
const apiKey = process.env.RESPOND_IO_API_KEY;

const results = [];

for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];
  if (!msg || msg.trim() === '') continue;

  // Delay 1.5s entre mensajes para simular escritura natural
  if (i > 0) {
    await new Promise(function(r) { setTimeout(r, 1500); });
  }

  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.respond.io/v2/contact/' + contactId + '/message',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        channelId: channelId,
        message: { type: 'text', text: msg }
      })
    });
    results.push({ success: true, index: i });
  } catch(e) {
    results.push({ success: false, index: i, error: e.message });
  }
}

return [{ json: { ...data, message_results: results } }];

